"""
Multi-Model Workflow Optimizer for OpenCode
Intelligent routing using smaller models for specific tasks and combining results
Based on model file sizes and resource optimization strategy
"""

import time
import asyncio
from typing import Dict, List, Optional, Tuple, Any
from dataclasses import dataclass, asdict
from enum import Enum
from collections import defaultdict

class ModelTier(Enum):
    """Model performance tiers based on size and capability"""
    ULTRA_LIGHT = "ultra_light"  # < 0.5GB - Quick verification, data parsing
    LIGHT = "light"              # 0.5-1GB - Simple tasks, fast responses
    MEDIUM = "medium"            # 1-3GB - Specialized workflows, coordination
    HEAVY = "heavy"              # 3GB+ - Complex reasoning, final synthesis

class TaskType(Enum):
    """Types of tasks for workflow optimization"""
    VERIFICATION = "verification"      # Quick yes/no, valid/invalid checks
    DATA_EXTRACTION = "data_extraction"  # Parse, extract, format data
    SIMPLE_GENERATION = "simple_generation"  # Quick code, explanations
    SPECIALIZED = "specialized"        # Domain-specific tasks
    COMPLEX_REASONING = "complex_reasoning"  # Multi-step logic
    FINAL_SYNTHESIS = "final_synthesis"  # Combine results into final output

@dataclass
class ModelCapability:
    """Represents a model's capabilities and resource profile"""
    name: str
    file_size_gb: float
    vram_percentage: float
    tier: ModelTier
    strengths: List[str]
    optimal_tasks: List[TaskType]
    max_concurrent_usage: float  # Max VRAM % when used with other models

@dataclass
class WorkflowStep:
    """Single step in a multi-model workflow"""
    step_id: str
    task_type: TaskType
    model_name: str
    prompt: str
    expected_output_type: str
    verification_required: bool = False
    timeout_seconds: int = 30
    depends_on: List[str] = None  # Previous step IDs this depends on

@dataclass
class WorkflowResult:
    """Result from a workflow step"""
    step_id: str
    model_used: str
    response: str
    execution_time: float
    success: bool
    confidence_score: float = 0.0
    verification_passed: bool = True
    metadata: Dict[str, Any] = None

class WorkflowOptimizer:
    """Optimizes task execution across multiple models based on size and capability"""

    def __init__(self, quant_manager, config):
        self.quant_manager = quant_manager
        self.config = config

        # Initialize model capabilities based on actual detected models
        self.model_capabilities = self._analyze_model_capabilities()

        # Workflow execution tracking
        self.active_workflows = {}
        self.execution_history = []

        # Resource management
        self.max_concurrent_vram = 80.0  # Max % VRAM to use concurrently
        self.current_vram_usage = 0.0

    def _analyze_model_capabilities(self) -> Dict[str, ModelCapability]:
        """Analyze available models and categorize by capability"""
        capabilities = {}

        # Get actual model data from quantization manager
        available_models = self.quant_manager.available_models
        total_vram = self.quant_manager.gpu_memory

        for model_name, model_info in available_models.items():
            size_gb = model_info['file_size_gb']
            vram_percentage = (size_gb / total_vram) * 100

            # Determine tier based on size
            if size_gb < 0.5:
                tier = ModelTier.ULTRA_LIGHT
                strengths = ['fast_verification', 'data_parsing', 'classification']
                optimal_tasks = [TaskType.VERIFICATION, TaskType.DATA_EXTRACTION]
                max_concurrent = vram_percentage * 3  # Can use multiple small models
            elif size_gb < 1.0:
                tier = ModelTier.LIGHT
                strengths = ['simple_generation', 'quick_responses', 'formatting']
                optimal_tasks = [TaskType.SIMPLE_GENERATION, TaskType.VERIFICATION]
                max_concurrent = vram_percentage * 2
            elif size_gb < 3.0:
                tier = ModelTier.MEDIUM
                if 'coder' in model_name.lower():
                    strengths = ['code_generation', 'debugging', 'technical_tasks']
                else:
                    strengths = ['balanced_reasoning', 'coordination', 'refinement']
                optimal_tasks = [TaskType.SPECIALIZED, TaskType.SIMPLE_GENERATION]
                max_concurrent = vram_percentage * 1.5
            else:
                tier = ModelTier.HEAVY
                strengths = ['complex_reasoning', 'synthesis', 'quality_assurance']
                optimal_tasks = [TaskType.COMPLEX_REASONING, TaskType.FINAL_SYNTHESIS]
                max_concurrent = vram_percentage  # Usually used alone

            capabilities[model_name] = ModelCapability(
                name=model_name,
                file_size_gb=size_gb,
                vram_percentage=vram_percentage,
                tier=tier,
                strengths=strengths,
                optimal_tasks=optimal_tasks,
                max_concurrent_usage=max_concurrent
            )

        return capabilities

    def design_optimal_workflow(self, user_request: str, mode: str = "auto") -> List[WorkflowStep]:
        """Design an optimal multi-model workflow for the user request"""

        # Analyze request complexity and type
        request_analysis = self._analyze_request(user_request)
        task_complexity = request_analysis['complexity']
        primary_domain = request_analysis['domain']
        estimated_steps = request_analysis['estimated_steps']

        # Determine resource budget based on mode
        resource_budget = self._get_resource_budget(mode)

        workflow_steps = []

        # Step 1: Initial processing with appropriate model
        if task_complexity == 'simple':
            # Use light model for simple tasks
            primary_model = self._select_model_by_tier(ModelTier.LIGHT, primary_domain)
            workflow_steps.append(WorkflowStep(
                step_id="primary_response",
                task_type=TaskType.SIMPLE_GENERATION,
                model_name=primary_model,
                prompt=user_request,
                expected_output_type="text"
            ))

        elif task_complexity == 'medium':
            # Use medium model with light verification
            primary_model = self._select_model_by_tier(ModelTier.MEDIUM, primary_domain)
            verification_model = self._select_model_by_tier(ModelTier.LIGHT)

            workflow_steps.extend([
                WorkflowStep(
                    step_id="primary_response",
                    task_type=TaskType.SPECIALIZED,
                    model_name=primary_model,
                    prompt=user_request,
                    expected_output_type="text"
                ),
                WorkflowStep(
                    step_id="verification",
                    task_type=TaskType.VERIFICATION,
                    model_name=verification_model,
                    prompt="Verify this response is accurate and complete: {primary_response}",
                    expected_output_type="boolean",
                    depends_on=["primary_response"]
                )
            ])

        else:  # complex
            # Multi-step workflow with verification
            if resource_budget >= 0.5:  # Auto or Think mode
                data_model = self._select_model_by_tier(ModelTier.ULTRA_LIGHT)
                primary_model = self._select_model_by_tier(ModelTier.HEAVY, primary_domain)
                verification_model = self._select_model_by_tier(ModelTier.MEDIUM)

                workflow_steps.extend([
                    WorkflowStep(
                        step_id="data_extraction",
                        task_type=TaskType.DATA_EXTRACTION,
                        model_name=data_model,
                        prompt=f"Extract key requirements from: {user_request}",
                        expected_output_type="structured_data"
                    ),
                    WorkflowStep(
                        step_id="primary_reasoning",
                        task_type=TaskType.COMPLEX_REASONING,
                        model_name=primary_model,
                        prompt="Based on requirements: {data_extraction}, provide detailed response to: " + user_request,
                        expected_output_type="text",
                        depends_on=["data_extraction"]
                    ),
                    WorkflowStep(
                        step_id="quality_check",
                        task_type=TaskType.VERIFICATION,
                        model_name=verification_model,
                        prompt="Review this response for accuracy and completeness: {primary_reasoning}",
                        expected_output_type="feedback",
                        depends_on=["primary_reasoning"]
                    )
                ])

                if resource_budget >= 0.75:  # Think mode - add synthesis
                    synthesis_model = self._select_model_by_tier(ModelTier.HEAVY)
                    workflow_steps.append(WorkflowStep(
                        step_id="final_synthesis",
                        task_type=TaskType.FINAL_SYNTHESIS,
                        model_name=synthesis_model,
                        prompt="Synthesize final response from: {primary_reasoning} with feedback: {quality_check}",
                        expected_output_type="text",
                        depends_on=["primary_reasoning", "quality_check"]
                    ))
            else:
                # Fast mode - single heavy model
                primary_model = self._select_model_by_tier(ModelTier.MEDIUM, primary_domain)
                workflow_steps.append(WorkflowStep(
                    step_id="fast_response",
                    task_type=TaskType.SPECIALIZED,
                    model_name=primary_model,
                    prompt=user_request,
                    expected_output_type="text"
                ))

        return workflow_steps

    def _analyze_request(self, request: str) -> Dict[str, Any]:
        """Analyze user request to determine workflow requirements"""
        request_lower = request.lower()

        # Determine complexity
        complexity_indicators = {
            'simple': ['quick', 'simple', 'short', 'basic'],
            'medium': ['explain', 'help', 'create', 'write'],
            'complex': ['analyze', 'design', 'optimize', 'complex', 'detailed', 'comprehensive']
        }

        complexity = 'medium'  # default
        for level, indicators in complexity_indicators.items():
            if any(indicator in request_lower for indicator in indicators):
                complexity = level
                break

        # Determine domain
        domain = 'general'
        if any(keyword in request_lower for keyword in ['code', 'function', 'debug', 'program']):
            domain = 'coding'
        elif any(keyword in request_lower for keyword in ['data', 'analyze', 'process']):
            domain = 'data'
        elif any(keyword in request_lower for keyword in ['explain', 'concept', 'understand']):
            domain = 'explanation'

        # Estimate steps needed
        estimated_steps = 1
        if complexity == 'medium':
            estimated_steps = 2
        elif complexity == 'complex':
            estimated_steps = 3 if len(request.split()) > 20 else 2

        return {
            'complexity': complexity,
            'domain': domain,
            'estimated_steps': estimated_steps,
            'word_count': len(request.split())
        }

    def _get_resource_budget(self, mode: str) -> float:
        """Get resource budget based on mode setting"""
        budget_map = {
            'fast': 0.25,
            'auto': 0.50,
            'think': 0.75
        }
        return budget_map.get(mode, 0.50)

    def _select_model_by_tier(self, tier: ModelTier, domain: str = None) -> str:
        """Select best model for given tier and optional domain"""
        candidates = [
            (name, cap) for name, cap in self.model_capabilities.items()
            if cap.tier == tier
        ]

        if not candidates:
            # Fallback to any available model
            candidates = list(self.model_capabilities.items())

        # Domain-specific selection
        if domain == 'coding':
            for name, cap in candidates:
                if 'coder' in name.lower():
                    return name

        # Select smallest in tier for efficiency
        candidates.sort(key=lambda x: x[1].file_size_gb)
        return candidates[0][0] if candidates else 'tinyllama'

    def get_workflow_summary(self, workflow_steps: List[WorkflowStep]) -> Dict[str, Any]:
        """Get summary of workflow resource usage and steps"""
        total_vram = 0.0
        models_used = set()

        for step in workflow_steps:
            model_cap = self.model_capabilities.get(step.model_name)
            if model_cap:
                total_vram += model_cap.vram_percentage
                models_used.add(step.model_name)

        return {
            'total_steps': len(workflow_steps),
            'models_used': list(models_used),
            'estimated_vram_usage': total_vram,
            'estimated_execution_time': sum(step.timeout_seconds for step in workflow_steps),
            'workflow_efficiency': len(models_used) / len(workflow_steps),  # Lower = more efficient
            'resource_distribution': {
                step.model_name: self.model_capabilities[step.model_name].vram_percentage
                for step in workflow_steps if step.model_name in self.model_capabilities
            }
        }

    def get_model_utilization_stats(self) -> Dict[str, Any]:
        """Get statistics about model utilization and capabilities"""
        stats = {
            'models_by_tier': defaultdict(list),
            'tier_capabilities': {},
            'resource_efficiency': {},
            'optimal_workflows': {}
        }

        for name, cap in self.model_capabilities.items():
            stats['models_by_tier'][cap.tier.value].append({
                'name': name,
                'size_gb': cap.file_size_gb,
                'vram_percent': cap.vram_percentage,
                'strengths': cap.strengths
            })

        # Tier capabilities summary
        for tier in ModelTier:
            tier_models = [cap for cap in self.model_capabilities.values() if cap.tier == tier]
            if tier_models:
                avg_size = sum(m.file_size_gb for m in tier_models) / len(tier_models)
                avg_vram = sum(m.vram_percentage for m in tier_models) / len(tier_models)
                stats['tier_capabilities'][tier.value] = {
                    'model_count': len(tier_models),
                    'avg_size_gb': avg_size,
                    'avg_vram_percent': avg_vram,
                    'total_vram_if_all_used': sum(m.vram_percentage for m in tier_models)
                }

        return stats